#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < K; i++) {
            int Li, Ri;
            scanf("%d %d", &Li, &Ri);
            int max_diff = 0;
            for (int j = Li - 1; j < Ri; j++) {
                for (int k = j + 1; k < Ri; k++) {
                    if (A[j] == A[k]) {
                        max_diff = (max_diff > k - j) ? max_diff : k - j;
                    }
                }
            }
            printf("%d\n", max_diff);
        }
    }
    return 0;
}

