import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < K; i++) {
                int Li = sc.nextInt();
                int Ri = sc.nextInt();
                int max_diff = 0;
                for (int j = Li - 1; j < Ri; j++) {
                    for (int k = j + 1; k < Ri; k++) {
                        if (A[j] == A[k]) {
                            max_diff = Math.max(max_diff, k - j);
                        }
                    }
                }
                System.out.println(max_diff);
            }
        }
    }
}

